create table if not exists organizations (id uuid primary key default gen_random_uuid(), org_key text not null unique, name text not null, created_at timestamptz not null default now());
create table if not exists organization_settings (id uuid primary key default gen_random_uuid(), organization_id uuid not null, settings jsonb not null, updated_at timestamptz not null);
create table if not exists organization_regions (id uuid primary key default gen_random_uuid(), organization_id uuid not null, country text not null, timezone text not null, currency text not null, updated_at timestamptz not null);
create table if not exists organization_quotas (id uuid primary key default gen_random_uuid(), organization_id uuid not null, quota_key text not null, quota_value numeric not null, updated_at timestamptz not null);
create table if not exists organization_security_policies (id uuid primary key default gen_random_uuid(), organization_id uuid not null, mfa_required boolean not null, ip_allowlist jsonb not null, updated_at timestamptz not null);
create table if not exists organization_permissions (id uuid primary key default gen_random_uuid(), organization_id uuid not null, role text not null, permission text not null, created_at timestamptz not null);
create table if not exists organization_session_policies (id uuid primary key default gen_random_uuid(), organization_id uuid not null, policy jsonb not null, updated_at timestamptz not null);
create table if not exists organization_device_policies (id uuid primary key default gen_random_uuid(), organization_id uuid not null, policy jsonb not null, updated_at timestamptz not null);
create table if not exists organization_ai_policies (id uuid primary key default gen_random_uuid(), organization_id uuid not null, provider text not null, token_budget int not null, autonomy_level text not null, updated_at timestamptz not null);
create table if not exists organization_ai_limits (id uuid primary key default gen_random_uuid(), organization_id uuid not null, limits jsonb not null, updated_at timestamptz not null);
create table if not exists organization_agent_permissions (id uuid primary key default gen_random_uuid(), organization_id uuid not null, agent_key text not null, enabled boolean not null, updated_at timestamptz not null);
create table if not exists organization_operational_limits (id uuid primary key default gen_random_uuid(), organization_id uuid not null, limits jsonb not null, updated_at timestamptz not null);
create table if not exists organization_feature_flags (id uuid primary key default gen_random_uuid(), organization_id uuid not null, flag_key text not null, enabled boolean not null, updated_at timestamptz not null);
create table if not exists organization_runtime_controls (id uuid primary key default gen_random_uuid(), organization_id uuid not null, control_key text not null, control_value numeric not null, updated_at timestamptz not null);
create table if not exists organization_compliance_rules (id uuid primary key default gen_random_uuid(), organization_id uuid not null, rule_key text not null, rule_value jsonb not null, updated_at timestamptz not null);
create table if not exists organization_retention_policies (id uuid primary key default gen_random_uuid(), organization_id uuid not null, policy jsonb not null, updated_at timestamptz not null);
create table if not exists organization_audit_exports (id uuid primary key default gen_random_uuid(), organization_id uuid not null, action text not null, payload jsonb not null, created_at timestamptz not null);
create table if not exists approval_requests (id uuid primary key default gen_random_uuid(), organization_id uuid not null, request_type text not null, requester text not null, status text not null, created_at timestamptz not null);
create table if not exists approval_decisions (id uuid primary key default gen_random_uuid(), request_id uuid not null, approver text not null, decision text not null, created_at timestamptz not null);
